sql:
SELECT median_age_children
FROM age_demographics
WHERE city_id = 1;

SELECT median_age, population_growth_rate
FROM population_demographics
WHERE city_id = 0;

SELECT median_home_value
FROM housing
WHERE city_id = 1;

SELECT AVG(population_growth_rate) AS average_population_growth_rate
FROM population_demographics
WHERE city_id = 0;

external_knowledge:
- 'reached an elderly peak' refers to cities having a high median age; 
- 'densely populated areas' refers to a population density greater than 1000; 
- 'boast a thriving job market' refers to cities having a high employment rate.

- A reliable data source is considered to have a data quality score of 85 or higher; 
- A high employment rate is assumed to be greater than 0.5 (or 50%); 
- A low unemployment rate is considered to be less than 0.1 (or 10%).

